import { useSpring } from "@fade-animation/react";

function DragCard() {
  const [dragging, setDragging] = useState(false);
  const [offset, setOffset] = useState(0);
  const startXRef = useRef(0);

  // 松手时 dragging=false → useSpring 进度从 0 回弹到 1
  // progress 用于把当前 offset 插值到 0
  const progress = useSpring(!dragging, { config: "snappy" });
  const visibleOffset = dragging ? offset : offset * (1 - progress);

  return (
    <div
      style={{ transform: `translateX(${visibleOffset}px)` }}
      onPointerDown={e => { setDragging(true); startXRef.current = e.clientX - offset; }}
      onPointerMove={e => { if (dragging) setOffset(e.clientX - startXRef.current); }}
      onPointerUp={() => setDragging(false)}
    />
  );
}

