import { useState } from "react";
import { useSpring } from "@fade-animation/react";

function SwipeCard({ onYes, onNo, onDismiss }) {
  const [offset, setOffset] = useState(0);
  const [settling, setSettling] = useState(false);
  const [target, setTarget] = useState(0);

  // 回弹/飞出时用 useSpring 驱动 offset → target
  const progress = useSpring(settling, { config: "snappy", onRest: () => {
    setSettling(false);
    if (Math.abs(target) > 0) onDismiss();
  } });
  const visible = settling ? offset + (target - offset) * progress : offset;

  function onPointerUp() {
    if (Math.abs(offset) > 120) {
      setTarget(offset > 0 ? window.innerWidth : -window.innerWidth);
      offset > 0 ? onYes() : onNo();
    } else {
      setTarget(0);
    }
    setSettling(true);
  }

  return (
    <div style={{
      transform: `translateX(${visible}px) rotate(${visible * 0.05}deg)`
    }} onPointerUp={onPointerUp} />
  );
}

