import { useState } from "react";
import { useSpring } from "@fade-animation/react";
// 手势推荐用 @use-gesture/react
import { usePinch } from "@use-gesture/react";

function ZoomImage() {
  const [scale, setScale] = useState(1);
  const [clamping, setClamping] = useState(false);
  const [target, setTarget] = useState(1);

  // 超出 [0.5, 3] 时回弹到边界
  const progress = useSpring(clamping, { config: "gentle", onRest: () => setClamping(false) });
  const visible = clamping ? scale + (target - scale) * progress : scale;

  const bind = usePinch(({ offset: [s], last }) => {
    setScale(s);
    if (last && (s < 0.5 || s > 3)) {
      setTarget(Math.max(0.5, Math.min(3, s)));
      setClamping(true);
    }
  });

  return <img {...bind()} style={{ transform: `scale(${visible})` }} />;
}

