import androidx.dynamicanimation.animation.*

val detector = ScaleGestureDetector(context, object : ScaleGestureDetector.SimpleOnScaleGestureListener() {
  override fun onScale(d: ScaleGestureDetector): Boolean {
    currentScale *= d.scaleFactor
    imageView.scaleX = currentScale
    imageView.scaleY = currentScale
    return true
  }

  override fun onScaleEnd(d: ScaleGestureDetector) {
    val clamped = currentScale.coerceIn(0.5f, 3f)
    if (clamped != currentScale) {
      SpringAnimation(imageView, DynamicAnimation.SCALE_X, clamped).apply {
        spring.dampingRatio = 0.7f
      }.start()
      SpringAnimation(imageView, DynamicAnimation.SCALE_Y, clamped).apply {
        spring.dampingRatio = 0.7f
      }.start()
      currentScale = clamped
    }
  }
})

